# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews.
# Category: xss

using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Data.Entity;
using System.Linq;
using System.Text;
using System.Web;
using System.Web.Mvc;

namespace MyApp.Controllers
{
    public class ProductsController : Controller
    {
        private readonly AppDbContext _db = new AppDbContext();

        [HttpGet]
        public ActionResult Details(int id)
        {
            var product = _db.Products.AsNoTracking().FirstOrDefault(p => p.Id == id);
            if (product == null) return HttpNotFound();

            var reviews = _db.Reviews
                .AsNoTracking()
                .Where(r => r.ProductId == id && r.IsApproved)
                .OrderByDescending(r => r.CreatedUtc)
                .Select(r => new ReviewViewModel
                {
                    Id = r.Id,
                    UserDisplayName = r.UserDisplayName,
                    CreatedUtc = r.CreatedUtc,
                    Rating = r.Rating,
                    Title = r.Title,
                    BodyHtml = ReviewFormatting.ToSafeBasicHtml(r.Body)
                })
                .ToList();

            var vm = new ProductDetailsViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = reviews
            };

            return View(vm);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(SubmitReviewInputModel input)
        {
            if (!ModelState.IsValid)
                return RedirectToAction("Details", new { id = input.ProductId });

            var productExists = _db.Products.Any(p => p.Id == input.ProductId);
            if (!productExists) return HttpNotFound();

            var review = new Review
            {
                ProductId = input.ProductId,
                UserDisplayName = string.IsNullOrWhiteSpace(input.UserDisplayName) ? "Anonymous" : input.UserDisplayName.Trim(),
                Title = input.Title?.Trim(),
                Body = input.Body ?? string.Empty,
                Rating = input.Rating,
                CreatedUtc = DateTime.UtcNow,
                IsApproved = true
            };

            _db.Reviews.Add(review);
            _db.SaveChanges();

            return RedirectToAction("Details", new { id = input.ProductId });
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing) _db.Dispose();
            base.Dispose(disposing);
        }
    }

    public class AppDbContext : DbContext
    {
        public AppDbContext() : base("DefaultConnection") { }

        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }

        protected override void OnModelCreating(DbModelBuilder modelBuilder)
        {
            base.OnModelCreating(modelBuilder);

            modelBuilder.Entity<Product>()
                .HasKey(p => p.Id);

            modelBuilder.Entity<Review>()
                .HasKey(r => r.Id);

            modelBuilder.Entity<Review>()
                .HasRequired(r => r.Product)
                .WithMany(p => p.Reviews)
                .HasForeignKey(r => r.ProductId)
                .WillCascadeOnDelete(true);
        }
    }

    public class Product
    {
