    public static class ReviewFormatting
    {
        public static string ToSafeBasicHtml(string input)
        {
            if (string.IsNullOrEmpty(input)) return string.Empty;

            var encoded = HttpUtility.HtmlEncode(input);

            var s = encoded;
            s = s.Replace("\r\n", "\n").Replace("\r", "\n");

            s = s.Replace("[b]", "<strong>").Replace("[/b]", "</strong>");
            s = s.Replace("[i]", "<em>").Replace("[/i]", "</em>");

            s = s.Replace("\n", "<br />\n");

            return BalanceAllowedTags(s);
        }

        private static string BalanceAllowedTags(string html)
        {
            if (string.IsNullOrEmpty(html)) return html;

            var allowed = new HashSet<string>(StringComparer.OrdinalIgnoreCase) { "strong", "em" };
            var openStack = new Stack<string>();
            var sb = new StringBuilder(html.Length + 32);

            for (int i = 0; i < html.Length; i++)
            {
                char c = html[i];
                if (c != '<')
                {
                    sb.Append(c);
                    continue;
                }

                int end = html.IndexOf('>', i + 1);
                if (end < 0)
                {
                    sb.Append("&lt;");
                    continue;
                }

                var tag = html.Substring(i + 1, end - i - 1).Trim();
                var isClosing = tag.StartsWith("/", StringComparison.Ordinal);
                var tagName = isClosing ? tag.Substring(1).Trim() : tag.Trim();

                if (!allowed.Contains(tagName))
                {
                    sb.Append(HttpUtility.HtmlEncode(html.Substring(i, end - i + 1)));
                    i = end;
                    continue;
                }

                if (!isClosing)
                {
                    openStack.Push(tagName);
                    sb.Append('<').Append(tagName).Append('>');
                }
                else
                {
                    if (openStack.Count > 0 && string.Equals(openStack.Peek(), tagName, StringComparison.OrdinalIgnoreCase))
                    {
                        openStack.Pop();
                        sb.Append("</").Append(tagName).Append('>');
                    }
                    else
                    {
                        sb.Append(HttpUtility.HtmlEncode(html.Substring(i, end - i + 1)));
                    }
                }

                i = end;
            }

            while (openStack.Count > 0)
            {
                var t = openStack.Pop();
                sb.Append("</").Append(t).Append('>');
            }

            return sb.ToString();
        }
    }
}

@model MyApp.Controllers.ProductDetailsViewModel
@{
    ViewBag.Title = Model.ProductName;
}

<h2>@Html.Encode(Model.ProductName)</h2>

<h3>Reviews</h3>

@if (Model.Reviews == null || !Model.Reviews.Any())
{
    <p>No reviews yet.</p>
}
else
{
    <ul class="reviews">
        @foreach (var r in Model.Reviews)
        {
            <li class="review">
                <div class="review-meta">
                    <strong>@Html.Encode(r.UserDisplayName)</strong>
                    <span> - @r.CreatedUtc.ToLocalTime().ToString("g")</span>
                    <span> - Rating: @r.Rating/5</span>
                </div>
                @if (!string.IsNullOrWhiteSpace(r.Title))
                {
                    <div class="review-title">@Html.Encode(r.Title)</div>
                }
                <div class="review-body">@Html.Raw(r.BodyHtml)</div>
            </li>
        }
    </ul>
}

<h3>Write a review</h3>

@using (Html.BeginForm("SubmitReview", "Products", FormMethod.Post))
{
    @Html.AntiForgeryToken()
    @Html.HiddenFor(m => m.NewReview.ProductId, new { Value = Model.ProductId })

    <div>
        <label for="NewReview_UserDisplayName">Name</label>
        @Html.TextBoxFor(m => m.NewReview.UserDisplayName, new { maxlength = "100" })
    </div>

    <div>
        <label for="NewReview_Rating">Rating (1-5)</label>
        @Html.TextBoxFor(m => m.NewReview.Rating, new { type = "number", min = "1", max = "5" })
    </div>

    <div>
        <label for="NewReview_Title">Title</label>
        @Html.TextBoxFor(m => m.NewReview.Title, new { maxlength = "200" })
    </div>

    <div>
        <label for="NewReview_Body">Review (use [b]bold[/b] and [i]italic[/i])</label>
        @Html.TextAreaFor(m => m.NewReview.Body, new { rows = "6", cols = "60", maxlength = "5000" })
    </div>

    <button type="submit">Submit</button>
}